import{_ as r,o as t,c as i,ag as a}from"./chunks/framework.YaIgwL5o.js";const m=JSON.parse('{"title":"Kinetic Text","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/kinetic-text.md","filePath":"tutorials/kinetic-text.md"}'),o={name:"tutorials/kinetic-text.md"};function l(n,e,d,s,h,p){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="kinetic-text" tabindex="-1">Kinetic Text <a class="header-anchor" href="#kinetic-text" aria-label="Permalink to &quot;Kinetic Text&quot;">​</a></h1><p>The Kinetic Text tool lets you insert animated text effects with a template gallery — no coding required.</p><h2 id="opening-the-gallery" tabindex="-1">Opening the gallery <a class="header-anchor" href="#opening-the-gallery" aria-label="Permalink to &quot;Opening the gallery&quot;">​</a></h2><p>Click the <strong>Kinetic</strong> button in the toolbar (next to Embed). A modal opens with a template grid, live preview, and parameter controls.</p><h2 id="workflow" tabindex="-1">Workflow <a class="header-anchor" href="#workflow" aria-label="Permalink to &quot;Workflow&quot;">​</a></h2><ol><li><strong>Pick a template</strong> from the left panel.</li><li><strong>Type your text</strong> in the text field.</li><li><strong>Adjust parameters</strong>: font, size, color, duration.</li><li>Watch the <strong>live preview</strong> update in real time.</li><li>Click <strong>Insert</strong> to place it on the current slide as an HTML embed element.</li></ol><p>After inserting, you can resize and reposition the element like any other. To edit the content later, double-click it to open the HTML editor.</p><h2 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h2><h3 id="typewriter" tabindex="-1">Typewriter <a class="header-anchor" href="#typewriter" aria-label="Permalink to &quot;Typewriter&quot;">​</a></h3><p>Characters appear one at a time with a blinking cursor, like text being typed.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-typewriter.html" style="width:100%;height:100px;border:none;"></iframe></div><h3 id="word-reveal" tabindex="-1">Word Reveal <a class="header-anchor" href="#word-reveal" aria-label="Permalink to &quot;Word Reveal&quot;">​</a></h3><p>Words fade and slide up one at a time with staggered timing.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-word-reveal.html" style="width:100%;height:100px;border:none;"></iframe></div><h3 id="revolve" tabindex="-1">Revolve <a class="header-anchor" href="#revolve" aria-label="Permalink to &quot;Revolve&quot;">​</a></h3><p>Text flips in from behind via a 3D Y-axis rotation, then drifts gently.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-revolve.html" style="width:100%;height:120px;border:none;"></iframe></div><h3 id="wave" tabindex="-1">Wave <a class="header-anchor" href="#wave" aria-label="Permalink to &quot;Wave&quot;">​</a></h3><p>Letters bob up and down in a staggered sine wave pattern.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-wave.html" style="width:100%;height:100px;border:none;"></iframe></div><h3 id="split-flap" tabindex="-1">Split-Flap <a class="header-anchor" href="#split-flap" aria-label="Permalink to &quot;Split-Flap&quot;">​</a></h3><p>Letters flip down like an airport departure board — each character rotates from the top.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-splitflap.html" style="width:100%;height:100px;border:none;"></iframe></div><h3 id="fade-cascade" tabindex="-1">Fade Cascade <a class="header-anchor" href="#fade-cascade" aria-label="Permalink to &quot;Fade Cascade&quot;">​</a></h3><p>Letters blur-in one by one, creating a progressive reveal.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-fade.html" style="width:100%;height:100px;border:none;"></iframe></div><h3 id="circular-orbit" tabindex="-1">Circular Orbit <a class="header-anchor" href="#circular-orbit" aria-label="Permalink to &quot;Circular Orbit&quot;">​</a></h3><p>Text arranged along a circle, continuously rotating.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-circular.html" style="width:100%;height:220px;border:none;"></iframe></div><h3 id="glitch" tabindex="-1">Glitch <a class="header-anchor" href="#glitch" aria-label="Permalink to &quot;Glitch&quot;">​</a></h3><p>Digital glitch with cyan and magenta color channel separation.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-glitch.html" style="width:100%;height:110px;border:none;"></iframe></div><h3 id="bounce-in" tabindex="-1">Bounce In <a class="header-anchor" href="#bounce-in" aria-label="Permalink to &quot;Bounce In&quot;">​</a></h3><p>Letters drop from above with spring-like overshoot.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-bounce.html" style="width:100%;height:110px;border:none;"></iframe></div><h3 id="stagger-from-center" tabindex="-1">Stagger from Center <a class="header-anchor" href="#stagger-from-center" aria-label="Permalink to &quot;Stagger from Center&quot;">​</a></h3><p>Letters pop outward from the center with rotation.</p><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/kinetic-stagger.html" style="width:100%;height:100px;border:none;"></iframe></div><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>After inserting, resize the element to fit your slide layout.</li><li>The generated HTML is self-contained — it works in exports and shared links.</li><li>To edit the animation after inserting, double-click the element to open the HTML editor.</li><li>Animations replay each time the slide becomes active in present mode.</li></ul>',40)])])}const u=r(o,[["render",l]]);export{m as __pageData,u as default};
